import { useState, useEffect, useCallback } from 'react';
import { api } from '../utils/api';

// Transform per-symbol results {AAPL:{total_return, sharpe, max_dd, trades}, ...}
// into the portfolio shape the dashboard/results pages expect
function transformResults(raw) {
  if (!raw) return null;

  // If it already has portfolio shape, return as-is
  if (raw.portfolio || raw.per_signal || raw.by_strategy) return raw;

  // Per-symbol keyed object → aggregate into portfolio
  const symbols = Object.entries(raw).filter(
    ([k, v]) => v && typeof v === 'object' && ('total_return' in v || 'trades' in v)
  );

  if (symbols.length === 0) return raw;

  let totalPnl = 0;
  let totalTrades = 0;
  let grossProfit = 0;
  let grossLoss = 0;
  let maxDd = 0;
  const perSignal = [];

  const byStrategy = {};

  symbols.forEach(([sym, data]) => {
    const ret = data.total_return || 0;
    const trades = data.trades || 0;
    const pnl = ret * 10000; // approximate $ PnL from return % on $10k
    totalPnl += pnl;
    totalTrades += trades;
    if (pnl >= 0) grossProfit += pnl;
    else grossLoss += Math.abs(pnl);
    if (data.max_dd != null && data.max_dd < maxDd) maxDd = data.max_dd;

    // Build per_signal entries
    perSignal.push({
      symbol: sym,
      strategy: 'default',
      region: 'us',
      pnl: pnl,
      total_return: ret,
      sharpe: data.sharpe || 0,
      max_dd: data.max_dd || 0,
      trades: trades,
    });

    // Group by strategy (use 'default' since API doesn't separate)
    if (!byStrategy['default']) {
      byStrategy['default'] = {
        total_pnl: 0, trades: 0, gross_profit: 0, gross_loss: 0,
        direction: 'LONG', symbols: [],
      };
    }
    byStrategy['default'].total_pnl += pnl;
    byStrategy['default'].trades += trades;
    if (pnl >= 0) byStrategy['default'].gross_profit += pnl;
    else byStrategy['default'].gross_loss += Math.abs(pnl);
    byStrategy['default'].symbols.push(sym);
  });

  // Calculate derived metrics (cap profit factor at 999 — sentinel for "no losses")
  const rawPf = grossLoss > 0 ? grossProfit / grossLoss : grossProfit > 0 ? 999.0 : 0;
  const pf = Math.min(rawPf, 999.0);
  const startingCapital = 10000;
  const netReturn = totalPnl / startingCapital;
  const winningTrades = perSignal.filter(s => s.pnl > 0).length;
  const winRate = perSignal.length > 0 ? (winningTrades / perSignal.length) * 100 : 0;

  // Build equity curve from cumulative PnL (sort by symbol for deterministic order)
  const sortedSignals = [...perSignal].sort((a, b) => a.symbol.localeCompare(b.symbol));
  let cumPnl = 0;
  const equityCurve = sortedSignals.map((s, i) => {
    cumPnl += s.pnl;
    return { x: i, equity: startingCapital + cumPnl, pnl: cumPnl };
  });

  // Strategy-level stats
  Object.entries(byStrategy).forEach(([stratName, st]) => {
    const stSignals = perSignal.filter(s => s.strategy === stratName);
    const stWinning = stSignals.filter(s => s.pnl > 0).length;
    st.win_rate = stSignals.length > 0 ? (stWinning / stSignals.length) * 100 : 0;
    const rawStPf = st.gross_loss > 0 ? st.gross_profit / st.gross_loss : st.gross_profit > 0 ? 999.0 : 0;
    st.profit_factor = Math.min(rawStPf, 999.0);
  });

  return {
    portfolio: {
      net_pnl: totalPnl,
      net_return_pct: netReturn * 100,
      profit_factor: pf,
      trades_executed: totalTrades,
      trades_skipped: 0,
      equity_curve: equityCurve,
      max_drawdown: maxDd * 100,
      win_rate: winRate,
      starting_capital: startingCapital,
      ending_equity: startingCapital + totalPnl,
      gross_profit: grossProfit,
      gross_loss: grossLoss,
    },
    total_signals: perSignal.length,
    total_pnl: totalPnl,
    gross_profit: grossProfit,
    gross_loss: grossLoss,
    profit_factor: pf,
    by_strategy: byStrategy,
    per_signal: perSignal,
    _raw: raw,
  };
}

export default function useBacktestData() {
  const [results, setResults] = useState(null);
  const [progress, setProgress] = useState(null);
  const [strategies, setStrategies] = useState([]);
  const [regionData, setRegionData] = useState({});

  const fetchAll = useCallback(async () => {
    const [resultsData, statusData, strategiesData, regionsData] = await Promise.all([
      api('/backtest/results'),
      api('/backtest/status'),
      api('/backtest/strategies'),
      api('/backtest/regions'),
    ]);

    if (resultsData) {
      setResults(transformResults(resultsData));
    }
    if (statusData) {
      setProgress(statusData);
    }
    if (strategiesData) {
      setStrategies(Array.isArray(strategiesData) ? strategiesData : strategiesData.strategies || []);
    }
    if (regionsData) {
      setRegionData(regionsData);
    }
  }, []);

  useEffect(() => {
    fetchAll();
    const interval = setInterval(fetchAll, 60000);  // 60s — backtest data changes slowly, was 10s
    return () => clearInterval(interval);
  }, [fetchAll]);

  return { results, progress, strategies, regionData };
}
